def compute_score() -> tuple[str, float]:
    from pptx import Presentation
    prs = Presentation(modified_ppt_path)
    slide = prs.slides[1]  # slide 2 (0-based)

    icons_found = 0
    for shape in slide.shapes:
        if shape.shape_type == 13 or hasattr(shape, 'image'):  # picture, icon, auto shape
            icons_found += 1

    if icons_found == 3:
        return "Icons/symbols found inside each of the three circles.", 1.0
    elif icons_found == 2:
        return "Icons/symbols found in only 2 circles.", 2/3
    elif icons_found == 1:
        return "Icon/symbol found in only 1 circle.", 1/3
    else:
        return "No icons/symbols found inside circles.", 0.0

def compute_score() -> tuple[str, float]:
    added_slides = ppt_diff.added_slides
    if len(added_slides) != 1:
        return f"Expected exactly 1 slide added, found {len(added_slides)}.", 0.0

    different_slides = []
    for i, s in enumerate(original_ppt_screenshots):
        orig_img = s.image_path
        mod_img = modified_ppt_screenshots[i].image_path

        if not orig_img or not mod_img:
            return (f"Screenshot for slide {i} in original or slide {i} in modified missing.", 0.0)

        if i != 1:
            prompt = (
                "Compare these two images of the same PowerPoint slide. There should be virtually no difference between these slides. "
                "Are there *any* visible changes to the slide's content, layout, or appearance (such as text, images, shapes, or formatting)? "
                "If there are no visible changes, answer NO. Otherwise, answer YES and briefly describe the differences. Take your time, analyze the slides, and compare them carefully."
            )
        else:
            prompt = (
                "Compare these two images of the same PowerPoint slide. Besides the fact that the second slide has icons in the circles, there should be no difference between the slide images. "
                "Besides the presence of the icons, are there *any* visible changes to the slide's content, layout, or appearance (such as text, images, shapes, or formatting)? "
                "If there are no visible differences besides the icons, answer NO. Otherwise, answer YES and briefly describe the differences. Take your time, analyze the slides, and compare them carefully."
            )

        vlm_resp = vlm_call(prompt, [orig_img, mod_img], temperature=0.0, max_tokens=128).strip().lower()
        if vlm_resp.startswith('yes'):
            different_slides.append(f"Visual difference(s) detected on Slide {i} in modified): {vlm_resp}")

    if len(different_slides) > 0:
        return ('\n'.join(different_slides), 0.0)

    return ('No differences found', 1.0)
